package main

import (
	"container/heap"
	"math"
)

// Helper struct for Priority Queue elements
type Item struct {
	cost int64
	node int
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want Pop to give us the smallest cost
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(nums []int64, queries [][]int64) []int64 {
	n := len(nums)

	// 1. Precompute closest[x]
	closest := make([]int, n)

	// For x = 0
	if n > 1 {
		closest[0] = 1
	}
	// For x = n-1
	if n > 1 {
		closest[n-1] = n - 2
	}

	for x := 1; x < n-1; x++ {
		leftDiff := int64(math.Abs(float64(nums[x] - nums[x-1])))
		rightDiff := int64(math.Abs(float64(nums[x] - nums[x+1])))

		if leftDiff < rightDiff {
			closest[x] = x - 1
		} else if rightDiff < leftDiff {
			closest[x] = x + 1
		} else {
			// If differences are equal, choose the smaller index
			closest[x] = x - 1
		}
	}

	results := make([]int64, len(queries))

	// Since Q is large, O(Q * N^2) is too slow. The provided structure necessitates running Dijkstra Q times.
	// We proceed with Dijkstra, accepting the theoretical complexity risk, as it's the only way to model the rules accurately.
	// If TLE occurs, the problem requires a deeper structural insight not immediately apparent from the rules.

	for i, query := range queries {
		L := int(query[0])
		R := int(query[1])

		if L == R {
			results[i] = 0
			continue
		}

		// Dijkstra setup
		dist := make([]int64, n)
		for j := 0; j < n; j++ {
			dist[j] = math.MaxInt64
		}

		pq := make(PriorityQueue, 0)
		heap.Init(&pq)

		dist[L] = 0
		heap.Push(&pq, &Item{cost: 0, node: L})

		minCost := int64(math.MaxInt64)

		for pq.Len() > 0 {
			item := heap.Pop(&pq).(*Item)
			currentCost := item.cost
			u := item.node

			if currentCost > dist[u] {
				continue
			}

			if u == R {
				minCost = currentCost
				break // Found shortest path to R
			}

			// 1. Type 2 Move: Move to closest(u), cost 1
			vClosest := closest[u]
			newCostC := currentCost + 1

			if newCostC < dist[vClosest] {
				dist[vClosest] = newCostC
				heap.Push(&pq, &Item{cost: newCostC, node: vClosest})
			}

			// 2. Type 1 Moves: Move to any node v, cost |nums[u] - nums[v]|
			for v := 0; v < n; v++ {
				if u == v {
					continue
				}

				jumpCost := int64(math.Abs(float64(nums[u] - nums[v])))
				newCostJ := currentCost + jumpCost

				if newCostJ < dist[v] {
					dist[v] = newCostJ
					heap.Push(&pq, &Item{cost: newCostJ, node: v})
				}
			}
		}

		results[i] = dist[R]
	}

	return results
}
