		heap []Item
	}

	func NewPriorityQueue() *PriorityQueue {
		return &PriorityQueue{heap: make([]Item, 0)}
	}

	func (pq *PriorityQueue) isEmpty() bool {
		return len(pq.heap) == 0
	}

	func (pq *PriorityQueue) swap(i, j int) {
		pq.heap[i], pq.heap[j] = pq.heap[j], pq.heap[i]
	}

	func (pq *PriorityQueue) compare(a, b Item) bool {
		return a.cost < b.cost
	}

	func (pq *PriorityQueue) bubbleUp(i int) {
		for i > 0 {
			parent := (i - 1) / 2
			if pq.compare(pq.heap[i], pq.heap[parent]) {
				pq.swap(i, parent)
				i = parent
			} else {
				break
			}
		}
	}

	func (pq *PriorityQueue) bubbleDown(i int) {
		n := len(pq.heap)
		for {
			left := 2*i + 1
			right := 2*i + 2
			smallest := i

			if left < n && pq.compare(pq.heap[left], pq.heap[smallest]) {
				smallest = left
			}
			if right < n && pq.compare(pq.heap[right], pq.heap[smallest]) {
