import (
	"container/heap"
	"math"
)

// PriorityQueue implementation for Dijkstra's algorithm
type Item struct {
	cost int64
	node int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(nums []int64, queries [][]int64) []int64 {
	n := len(nums)

	// 1. Precompute closest[x]
	closest := make([]int, n)

	// For x = 0
	if n > 1 {
		closest[0] = 1
	}
	// For x = n-1
	if n > 1 {
		closest[n-1] = n - 2
	}

	for x := 1; x < n-1; x++ {
		leftDiff := abs(nums[x] - nums[x-1])
		rightDiff := abs(nums[x] - nums[x+1])

		if leftDiff < rightDiff {
			closest[x] = x - 1
		} else if rightDiff < leftDiff {
			closest[x] = x + 1
		} else {
			// If differences are equal, choose the smaller index
			closest[x] = x - 1
		}
	}

	results := make([]int64, len(queries))

	// Run Dijkstra's algorithm for each query
	for qIdx, query := range queries {
		L := int(query[0])
		R := int(query[1])

		if L == R {
			results[qIdx] = 0
			continue
		}

		dist := make([]int64, n)
		for i := range dist {
			dist[i] = math.MaxInt64
		}

